           c.sprite = LookupSprite("img_listbg");
        }
        { var c = goMap[991114413994975951L].AddComponent<Button>();
           c.enabled = true;
        }
        { var c = goMap[-7872418442447676584L].AddComponent<Text>();
           c.text = "属性";
